import os
from sky.clouds.aws import AWS

def test_aws_check_credentials_requires_static_credentials_when_not_sso__a1(tmp_path):
    """If not using SSO, ~/.aws/credentials must exist, otherwise check_credentials
    should fail.

    Before fix: returns (True, hints) even if credentials file is missing.
    After fix: returns (False, "...~/.aws/credentials does not exist...") if not SSO.
    """
    os.environ['HOME'] = str(tmp_path)
    aws_dir = tmp_path / '.aws'
    aws_dir.mkdir(parents=True, exist_ok=True)
    cloud = AWS()
    cloud._is_current_identity_sso = lambda: False
    cloud.get_current_user_identity = lambda: 'dummy-user-id'
    ok, msg = cloud.check_credentials()
    assert ok is False, f'AWS.check_credentials() must fail when not using SSO and ~/.aws/credentials is missing (static credentials required for multi-cloud). Got ok={ok}, msg={msg!r}'

